import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Dynamically allocating a buffer based on input length
        byte[] buffer = new byte[userInput.length()];
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, userInput.length());

        // Printing the buffer contents
        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
